        const iframeSrc = await page.evaluate((el) => el?.getAttribute('src'), iframe)
        console.log(`${app.title} — iframe src: ${iframeSrc}`)
        expect(iframeSrc).toContain(app.urlPattern)
        // Verify theme is forwarded to iframe URL
